# Example Vault policy (Cedar-style pseudocode)
policy:
  - name: "agent-read-customer-data"
    permit:
      principal: { agent_role: "customer-support-agent" }
      action: { scope: ["db:read:customers", "db:read:orders"] }
      resource: { type: "database", name: "prod-customers" }
      conditions:
        - ttl_max: "15m"
        - task_id: required  # must provide a task context

  - name: "deny-all-writes-to-prod"
    forbid:
      principal: { agent_role: "customer-support-agent" }
      action: { scope: ["db:write:*", "db:delete:*"] }
      resource: { env: "production" }

# Tool wrapper with scoped credential fetching
import time
from dataclasses import dataclass
from typing import Any
import httpx

@dataclass
class ScopedToken:
    token: str
    expires_at: float
    scope: str

    def is_valid(self, buffer_seconds: int = 60) -> bool:
        return time.time() < (self.expires_at - buffer_seconds)


class CredentialVaultClient:
    def __init__(self, vault_url: str, agent_id: str, task_id: str):
        self.vault_url = vault_url
        self.agent_id = agent_id
        self.task_id = task_id
        self._cache: dict[str, ScopedToken] = {}

    def get_token(self, scope: str) -> str:
        """Return a cached token if still valid, otherwise fetch a new one."""
        cached = self._cache.get(scope)
        if cached and cached.is_valid():
            return cached.token

        response = httpx.post(
            f"{self.vault_url}/v1/credentials",
            json={
                "agent_id": self.agent_id,
                "task_id": self.task_id,
                "scope": scope,
            },
            headers={"Authorization": f"Bearer {self._agent_identity_token()}"},
            timeout=5,
        )
        response.raise_for_status()
        data = response.json()

        token_obj = ScopedToken(
            token=data["token"],
            expires_at=data["expires_at"],
            scope=scope,
        )
        self._cache[scope] = token_obj
        return token_obj.token

    def revoke_all(self) -> None:
        """Revoke all credentials issued to this task on completion."""
        httpx.post(
            f"{self.vault_url}/v1/revoke",
            json={"task_id": self.task_id},
            headers={"Authorization": f"Bearer {self._agent_identity_token()}"},
        )
        self._cache.clear()

    def _agent_identity_token(self) -> str:
        # In production, this comes from the agent's workload identity provider
        # (e.g., GCP service account, AWS instance profile, SPIFFE/SPIRE)
        return "agent-identity-token-placeholder"


def make_scoped_db_tool(vault: CredentialVaultClient):
    """Wrap a database tool with per-call scoped credential fetching."""
    def query_customers(sql: str) -> list[dict]:
        token = vault.get_token(scope="db:read:customers")
        # Pass the scoped token as the database credential
        with db_connect(token=token) as conn:
            return conn.execute(sql).fetchall()
    return query_customers


