# Customer support agent with per-tool scoped credentials
from typing import Optional

class CustomerSupportAgent:
    def __init__(self, vault: CredentialVaultClient, task_id: str):
        self.vault = vault
        self.task_id = task_id

    def handle_query(self, customer_id: str, issue_type: str) -> dict:
        try:
            # Each tool gets only the scope it needs
            customer = self._fetch_customer(customer_id)
            orders = self._fetch_orders(customer_id)
            shipping = self._fetch_shipping(orders[-1]["tracking_id"])

            if issue_type == "refund" and self._user_verified():
                # Refund credential only requested when actually needed
                result = self._process_refund(
                    order_id=orders[-1]["id"],
                    amount=orders[-1]["total"],
                )
                return {"action": "refund_issued", **result}

            return {
                "customer": customer,
                "recent_order": orders[-1],
                "shipping": shipping,
            }
        finally:
            self.vault.revoke_all()  # Clean up all issued credentials

    def _fetch_customer(self, customer_id: str) -> dict:
        token = self.vault.get_token(f"crm:read:customer:{customer_id}")
        return crm_client.get(customer_id, token=token)

    def _fetch_orders(self, customer_id: str) -> list:
        token = self.vault.get_token(f"orders:read:by_customer:{customer_id}")
        return orders_client.list(customer_id, token=token)

    def _fetch_shipping(self, tracking_id: str) -> dict:
        token = self.vault.get_token("shipping:read:status")
        return shipping_client.status(tracking_id, token=token)

    def _process_refund(self, order_id: str, amount: float) -> dict:
        # Narrow TTL: refund credential valid for 2 minutes max
        token = self.vault.get_token(f"payments:write:refund:order:{order_id}")
        return payments_client.refund(order_id, amount, token=token)

